#!/usr/bin/env python3
import os, base64

files = [
  ('lib\\\\sync\\\\engine.ts', ''),
  ('lib\\\\pos\\\\personalkollen.ts', ''),
  ('lib\\\\pos\\\\caspeco.ts', ''),
  ('lib\\\\pos\\\\ancon.ts', ''),
  ('lib\\\\pos\\\\swess.ts', ''),
  ('app\\\\forecast\\\\page.tsx', ''),
  ('app\\\\api\\\\forecast\\\\route.ts', ''),
  ('app\\\\api\\\\integrations\\\\generic\\\\route.ts', ''),
  ('app\\\\integrations\\\\page.tsx', ''),
  ('components\\\\Sidebar.tsx', ''),
  ('lib\\\\ai\\\\buildContext.ts', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Forecast page + all POS adapters + full sync\" && vercel --prod")
